1710	\section{Separatedness}
1711	\label{sec:gr_separated}
1712	
1713	The surjectivity of the restricted-diagonal comorphism is the ring-theoretic
1714	heart of separatedness. We isolate it through the following sequence of
1715	helper results before stating the keystone lemma.
1716	
1717	\begin{lemma}
1718	
1719	\leanok
1720	[Two-sided inverse identity \(\tilde\theta_{I,J}(P^J_I)\,P^I_J = 1\)]
1721	  \label{lem:gr_transitionPreMap_minorDet_swap_mul}
1722	  \lean{AlgebraicGeometry.Grassmannian.transitionPreMap_minorDet_swap_mul}
1723	  \uses{lem:gr_universalMatrix_map_transitionPreMap, lem:gr_transition_pre_unit, lem:gr_transitionPreMap_minorDet}
1724	  In \(R^I_J = \mathbb{Z}[X^I, 1/P^I_J]\), the pre-localisation transition hom
1725	  \(\tilde\theta_{I,J}\) (\cref{def:gr_transition_pre}) satisfies the explicit
1726	  two-sided inverse identity
1727	  \[
1728	    \tilde\theta_{I,J}\bigl(P^J_I\bigr) \cdot P^I_J \;=\; 1 .
1729	  \]
1730	  This refines the unit assertion of \cref{lem:gr_transition_pre_unit} to a named
1731	  inverse: \(\tilde\theta_{I,J}(P^J_I)\) is the explicit inverse of \(P^I_J\) in
1732	  \(R^I_J\).
1733	\end{lemma}
1734	\begin{proof}
1735	  \uses{lem:gr_universalMatrix_map_transitionPreMap, lem:gr_transition_pre_unit, lem:gr_transitionPreMap_minorDet}
1736	  \leanok
1737	  By \cref{lem:gr_transitionPreMap_minorDet} (taking the third subset \(K = I\)),
1738	  \(\tilde\theta_{I,J}(P^J_I)\) is the determinant of the \(I\)-minor of the image
1739	  matrix \(M = (X^I_J)^{-1} X^I\), which by
1740	  \cref{lem:gr_universalMatrix_map_transitionPreMap} equals
1741	  \(\det\bigl((X^I_J)^{-1} X^I_I\bigr) = \det\bigl((X^I_J)^{-1}\bigr)\). Hence
1742	  \(\tilde\theta_{I,J}(P^J_I) = \det(X^I_J)^{-1}\), and multiplying by \(P^I_J =
1743	  \det(X^I_J)\) gives \(\det(X^I_J)^{-1} \cdot \det(X^I_J) = 1\) by the
1744	  localisation-inverse cancellation for the unit \(\det(X^I_J)\)
1745	  (\cref{lem:gr_transition_pre_unit}).
1746	\end{proof}
