1748	\begin{definition}
1749	
1750	\leanok
1751	[Restricted-diagonal comorphism \(\delta_{I,J}\)]
1752	  \label{def:gr_diagonalRingMap}
1753	  \lean{AlgebraicGeometry.Grassmannian.diagonalRingMap}
1754	  \uses{def:gr_transition_pre}
1755	  The \emph{restricted-diagonal comorphism} on the patch \(U^I \times_{\mathbb{Z}}
1756	  U^J\) is the \(\mathbb{Z}\)-algebra homomorphism
1757	  \[
1758	    \delta_{I,J} : \mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]
1759	    \longrightarrow R^I_J,
1760	    \qquad
1761	    X^I \otimes 1 \mapsto X^I, \quad
1762	    1 \otimes X^J \mapsto (X^I_J)^{-1} X^I,
1763	  \]
1764	  whose surjectivity is the content of separatedness; this is the \(\delta_{I,J}\)
1765	  of \cref{lem:gr_separated}.
1766	\end{definition}
1767	\begin{proof}
1768	  \uses{def:gr_transition_pre}
1769	  \leanok
1770	  Construct \(\delta_{I,J}\) as the tensor-product lift of the two commuting
1771	  factors: the structure map \(\mathbb{Z}[X^I] = R^I \to R^I_J\) on the left
1772	  factor, and the pre-localisation transition hom \(\tilde\theta_{I,J}\)
1773	  (\cref{def:gr_transition_pre}) on the right factor. Since both land in the
1774	  commutative ring \(R^I_J\), the universal property of the tensor product of
1775	  \(\mathbb{Z}\)-algebras yields a unique \(\mathbb{Z}\)-algebra homomorphism out
1776	  of \(\mathbb{Z}[X^I] \otimes_{\mathbb{Z}} \mathbb{Z}[X^J]\) restricting to these
1777	  factors; by construction its right component is \(\tilde\theta_{I,J}\).
